RoleModel _$RoleModelFromJson(Map<String, dynamic> json) => RoleModel(
      value: json['value'] as String,
    );

Map<String, dynamic> _$RoleModelToJson(RoleModel instance) => <String, dynamic>{
      'value': instance.value,
    };
